INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00117', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Reppetto（1976）認為一般的犯罪轉移共有6種犯罪轉移，如派出所轄區實施社區守望相助，只 有一半的家戶參加守望相助，竊盜者轉移對未參加社區守望相助的家戶下手，此類犯罪轉移屬於 下列那一種？', '["加害人轉移", "地區轉移", "標的轉移", "類型轉移"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00118', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '犯罪預防由公共醫療模式角度可區分為三個層次：初級、次級與三級預防，下列有關三級預防的 陳述，何者是錯誤的？', '["警察加強巡邏，警察的出現降低被害恐懼感，這策略屬於初級預防", "初級犯罪預防有時也包括廣泛的社會預防，包括失業、貧困等所導致的異常行為之預防", "「情境犯罪預防」是常被採用的次級預防", "次級犯罪預防也包含預防其他偏差行為所導致之犯罪，包括安非他命使用者強制戒治後的復歸 社會，以避免其犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00119', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '我國行政程序法第11條管轄法定及第19條職務協助的規定，從法治國理念說明我國應信守「組 織法定原則」及「管轄恆定原則」。檢調、海巡、移民等機關亦負有危害防止任務，一般行政機 關之環保、衛生、消防、建管等單位皆亦負有防止危害任務。各機關間應強化橫向溝通、調和等 作為，以發揮治理功效。這種行政權本身危害防止任務的合作較傾向於下列那一類？', '["警察權之水平分配", "警察權之比例原則", "警察權之責任原則", "警察權之垂直分配"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00120', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '「證據為基礎之犯罪預防」（Evidence-BasedCrimePrevention）是由美國犯罪學家Sherman 教授 等（2002）所提出。其認為有效的公共政策及實務作為需要以科學證據為基礎。Sherman教授等 人（2002）評估實行犯罪預防的七種機構環境的有效性。這七種主要的機構環境包括那些？', '["家庭、學校、社區、娛樂場所、車站、警察機關、法院與矯治", "家庭、學校、社區、交通場所、都市、警察機關、法院與矯治", "家庭、學校、社區、證券市場、宗教、警察機關、法院與矯治", "家庭、學校、社區、勞動市場、地方、警察機關、法院與矯治"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00121', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Stone（1997）將政策分析架構分為目標（goals）、問題（problems）與解決（solutions）等三部 分，下列有關政策分析架構論述，何者錯誤？', '["目標是政治行動者政治目的的表達，問題是在說明目標與現狀是如何的不一致，解答是如何將 現狀轉變成符合目標的方案", "「問題」指的是目標與現狀的差異，但卻被政治所定義和呈現，政治人物或決策者運用符號、 數字、因果推論、利益及決策等策略解釋或說明他們理解的公共政策", "Stone標示了「公平（equity）、效率（efficiency）、福祉（welfare）、安全（security）、自由 （liberty）」等公共政策追求的價值面向", "理性決策是一種客觀性地描繪及定義政策問題的方法，包括4步驟：確定目標、尋找方法、選 擇、成效，Stone深表認同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00122', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '依據Sabatier和Mazmanian（1983）的政策執行環境關聯模式，下列何者正確？', '["「問題的可處置性」是環境自變項之一，其內容包括「選民團體的態度與資源」", "「影響執行的非法令規章因素」是環境自變項之一，其內容包括「外圍分子的正式接近程度」", "「影響執行的法令規章因素」是環境自變項之一，其內容包括「正確因果理論的結合」", "執行機關政策產出、標的團體對該政策的服從、政策的實際影響、執行機構間與內部的階層整 合、法令修正等階段，這5個階段是政策執行的依變項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00123', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '下列有關第三造警政的內容，何者正確？', '["第三造對象包括社區居民、犯罪加害人、犯罪加害人家屬、財產所有人、場所管理者、企業負 責人等", "由警察發起第三造警政之作為，可先透過要求配合、諮詢合作等較溫和方式，促使犯罪加害人 自願參與犯罪預防活動；若其不願參與，則利用勸說或由行政機關制定相關法律規範等強制方 法，使其承擔責任、履行義務，避免遭受裁罰", "社區警政為第三造警政興起原因之一，因社區警政無課責機制，故提倡以法律課責之第三造警 政策略，強化警察責任及犯罪偵查之成效", "情境犯罪預防為第三造警政的執行方法之一，情境犯罪預防不參與問題分析過程，直接運用不 同情境技術因應物理環境的失序；第三造警政則參與問題分析，並透過相關法規範予以課責"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00124', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關各國警政策略發展趨勢，下列何者錯誤？', '["社區警政約於1980年代中期被提出，美國原設有鄉鎮村里等行政區域，Bayley以「社區」之 概念簡稱鄉鎮村里等行政區域，提出「社區警政」的概念", "「第三造警政」的概念起源於澳洲，萌生於1980年代後期，並在英國被廣為應用。其目的是 進行犯罪預防及犯罪控制，認為犯罪預防工作是犯罪控制中的一環，主要藉由犯罪預防以控制 未來可能導致犯罪的潛在問題", "1994年紐約市警察局局長William Bratton將紐約地區的犯罪紀錄加以彙整，建立成有系統的 資料庫，再進一步對資料庫的犯罪資訊進行分析，以擬定治安管理的適宜策略，這即是「電腦 統計警政」之起源", "美國於2001年發生「911事件」，開始重視國土安全的維護，並強調各聯邦執法機關間必須分 享相關情報，警察機關發展出「情報導向警政」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00125', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警察於街頭執法時，面對各種執法情境，經常需要行使強制力，依據Skolnick&Fyfe（1993：38-39） 歸納之警察控制街頭秩序的強制力程度，下列何者不是Skolnick&Fyfe所提出的強制力分類？', '["口頭勸導（persuasiveverbalization）：當警察現身仍未達目的時，警察以堅定但非命令的口吻 勸導當事人", "制伏命令（paincommand）：警察在不傷害當事人前提下制伏當事人，並以命令式的語氣告知 當事人警察的要求", "運用裝備控制（impacttechniques）：此措施是對付反抗者的作為，使用警棍或瓦斯槍等，但不 傷害到性命", "致命性強制力（deadlyforce）：針對明顯危害他人生命者或暴力犯逃犯，當對方不聽警察命令 時，警察得依據法令使用槍械"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00126', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '犯罪預防的標的是犯罪，了解犯罪須借助犯罪測量的方法，其中之一為犯罪被害調查法，下列何 者不是犯罪被害調查法的優點？', '["可以彌補官方統計及自陳報告問卷調查兩種犯罪測量方法的不足", "可以調查所有的犯罪類型", "了解犯罪被害民眾未向警方報案的原因", "了解被害者特性、被害者之情境等導致被害的各種因素，可以及早進行犯罪預防"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
